from dataclasses import dataclass, field
from enum import Enum


class StepStatus(Enum):
    PENDING = "pending"
    IN_PROGRESS = "in_progress"
    DONE = "done"
    FAILED = "failed"


@dataclass
class PlanStep:
    title: str
    status: StepStatus = StepStatus.PENDING
    result: str = ""


@dataclass
class AgentPlan:
    steps: list[PlanStep] = field(default_factory=list)

    def set_plan(self, titles: list[str]) -> None:
        self.steps = [PlanStep(title=t) for t in titles]

    def start(self, title: str) -> None:
        for s in self.steps:
            if s.title == title:
                s.status = StepStatus.IN_PROGRESS

    def complete(self, title: str, result: str = "") -> None:
        for s in self.steps:
            if s.title == title:
                s.status = StepStatus.DONE
                s.result = result

    def fail(self, title: str, reason: str = "") -> None:
        for s in self.steps:
            if s.title == title:
                s.status = StepStatus.FAILED
                s.result = reason

    def next_pending(self) -> PlanStep | None:
        for s in self.steps:
            if s.status == StepStatus.PENDING:
                return s
        return None

    def is_complete(self) -> bool:
        return all(s.status in (StepStatus.DONE, StepStatus.FAILED) for s in self.steps)

    def summary(self) -> str:
        icons = {
            StepStatus.PENDING: "[ ]",
            StepStatus.IN_PROGRESS: "[~]",
            StepStatus.DONE: "[x]",
            StepStatus.FAILED: "[!]",
        }
        return "\n".join(f"{icons[s.status]} {s.title}" for s in self.steps)

import json
import pathlib
from dataclasses import dataclass, field, asdict


@dataclass
class PersistentScratchpad:
    """
    Scratchpad that survives process restarts by saving to a JSON file.
    Use for tasks that may span multiple agent sessions.
    """
    task_id: str
    files_read: list[str] = field(default_factory=list)
    findings: list[dict] = field(default_factory=list)
    notes: str = ""

    @classmethod
    def load_or_create(cls, task_id: str, save_dir: str = "/tmp/agent_state") -> "PersistentScratchpad":
        path = pathlib.Path(save_dir) / f"{task_id}.json"
        if path.exists():
            data = json.loads(path.read_text())
            return cls(**data)
        return cls(task_id=task_id)

    def save(self, save_dir: str = "/tmp/agent_state") -> None:
        path = pathlib.Path(save_dir) / f"{self.task_id}.json"
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(asdict(self), indent=2))

    def delete(self, save_dir: str = "/tmp/agent_state") -> None:
        path = pathlib.Path(save_dir) / f"{self.task_id}.json"
        path.unlink(missing_ok=True)

    def summary(self) -> str:
        parts = []
        if self.files_read:
            parts.append(f"Files examined: {len(self.files_read)}")
        if self.findings:
            parts.append(f"Findings so far: {len(self.findings)}")
        if self.notes:
            parts.append(f"Notes: {self.notes[:300]}")
        return "\n".join(parts) if parts else "Scratchpad: empty"


