import pytest
from dataclasses import dataclass, field


class TestAgentScratchpad:
    def _make(self):
        return AgentScratchpad()

    def test_empty_summary(self):
        s = self._make()
        assert s.summary() == "Scratchpad: empty"

    def test_files_appear_in_summary(self):
        s = self._make()
        s.files_read = ["a.py", "b.py"]
        assert "a.py" in s.summary()
        assert "b.py" in s.summary()

    def test_partial_result_truncated(self):
        s = self._make()
        s.partial_result = "x" * 500
        summary = s.summary()
        assert len(summary) < 600  # truncated in summary()


