class TestAgentPlan:
    def _make(self):
        p = AgentPlan()
        p.set_plan(["read files", "fix bug", "run tests"])
        return p

    def test_next_pending_initial(self):
        p = self._make()
        assert p.next_pending().title == "read files"

    def test_complete_advances_pending(self):
        p = self._make()
        p.complete("read files")
        assert p.next_pending().title == "fix bug"

    def test_is_complete_when_all_done(self):
        p = self._make()
        for step in p.steps:
            step.status = StepStatus.DONE
        assert p.is_complete() is True
